#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        char s[100005]; scanf("%s",s);
        int freq[26]={0};
        for(int i=0;i<N;i++) freq[s[i]-'a']++;
        int distinct=0; for(int i=0;i<26;i++) if(freq[i]) distinct++;
        char ans[100005]; int pos=0; int possible=1;
        while(N>0 && possible){
            int placed=0;
            for(int c=0;c<26;c++) if(freq[c]){
                freq[c]--;
                int mx=0,mn=1e9;
                for(int j=0;j<26;j++) if(freq[j]|| (freq[j]==0 && (freq[j]+0)>=0 && (freq[j]+0)<=N)){
                    // consider only characters that were present originally (freq[j] may become 0)
                    mx = mx>freq[j]?mx:freq[j];
                    mn = mn<freq[j]?mn:freq[j];
                }
                if(mx-mn<=K){
                    ans[pos++]=c+'a';
                    placed=1; break;
                }
                freq[c]++; // revert
            }
            if(!placed){ possible=0; }
            N--;
        }
        if(!possible) printf("-1\n");
        else{ ans[pos]='\0'; printf("%s\n",ans); }
    }
    return 0;
}

