const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for(let t=0;t<T;t++){
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const S = input[idx++];
  const freq = Array(26).fill(0);
  for(const ch of S) freq[ch.charCodeAt(0)-97]++;
  let ans = '';
  let possible = true;
  for(let rem=N; rem>0; rem--){
    let placed = false;
    for(let c=0;c<26;c++) if(freq[c]>0){
      freq[c]--;
      const mx = Math.max(...freq);
      const mn = Math.min(...freq);
      if(mx - mn <= K){
        ans += String.fromCharCode(97+c);
        placed = true;
        break;
      }
      freq[c]++;
    }
    if(!placed){ possible = false; break; }
  }
  outputs.push(possible ? ans : '-1');
}
